import { ScaleOrdinal } from 'd3-scale';

import { buildCategoricalItemsFromScale } from './utils.js';
import { useChartLayoutOrientation } from '../../../core/components/chart-layout/hooks/useChartLayoutOrientation.js';
import { getLegendOrientation } from '../../../core/components/chart-layout/utils/orientation.js';
import { ChartLegend } from '../../../core/components/legend/categorical/ChartLegend.js';
import { LegendItem } from '../../../core/components/legend/categorical/types/legend.js';
import { useColorRuleConfig } from '../../../core/context/ColorRuleContext.js';
import { useHoneycombBaseScale } from '../../hooks/use-honeycomb-base-scale.js';
import { useHoneycombTruncationMode } from '../../hooks/use-honeycomb-truncation-mode.js';
import { useSetStateSelection } from '../../store/store.js';

export const HoneycombCategoricalLegendRenderer = () => {
  const { orientation: layoutOrientation } = useChartLayoutOrientation();
  const truncationMode = useHoneycombTruncationMode();
  const scale = useHoneycombBaseScale() as ScaleOrdinal<string, string>;
  const updateStateSelection = useSetStateSelection();
  const colorRules = useColorRuleConfig();
  const items = buildCategoricalItemsFromScale(scale, colorRules);

  const orientation = getLegendOrientation(layoutOrientation);

  const handleHover = (hoveredItem?: LegendItem) => {
    updateStateSelection({ hovered: hoveredItem });
  };

  return (
    <ChartLegend
      items={items}
      orientation={orientation}
      onHover={handleHover}
      truncationMode={truncationMode}
      interactionsDisabled
    />
  );
};
